(function(){const sidebar=document.querySelector(".sidebar");const logo=document.querySelector(".logo");logo.setAttribute("class","menu-logo");document.querySelector(".main-sidebar").insertBefore(logo,sidebar);$.AdminLTE.options['animationSpeed']=200;const observer=new MutationObserver(mutations=>{mutations.forEach(mutation=>{if(mutation.attributeName!="class")return;if(!mutation.target.classList.contains("active"))return;const ul=mutation.target.querySelector("ul");if(!ul)return;Array.from(ul.querySelectorAll("a")).forEach(element=>{if(element.href!=location.origin+location.pathname)return;element.parentElement.setAttribute("class","active")})})});document.querySelectorAll(".sidebar-menu>li").forEach(element=>{observer.observe(element,{"attributes":true})})})();